def build_feedback(prediction: ModelPrediction) -> ResearchFeedback:
    title,explanation,question,action,repeat=RULES[prediction.lab_id][prediction.predicted_class]
    evidence=[f"Уверенность модели: {prediction.confidence*100:.1f}%"]
    for k,v in sorted(prediction.features.items(),key=lambda x:abs(x[1]),reverse=True)[:3]:
        evidence.append(f"{k}: {v:.4f}")
    return ResearchFeedback(title,explanation,evidence,question,action,"Рекомендуется проверка преподавателем.",repeat)
